const somePage: FunctionComponent<~Props> = function(){
	const listTabs = useMemo(()=>
		data.reduce((list, {node:{ frontmatter: { querys }}}) =>{
			querys.forEach((query)=>{
				query in list ? list[query]++ : (list[query] = 1)
			})
			list['All']++
			return list
		},{ All: 0 })
	,[])

	const data = useMemo(() => (
