### 제한시간 타이머
```js
const createCountdown = (limitTime) =>{
	const displayElement = document.querySelector('.printTime');
	if (!displayElement) return;

	let tickSetTimeout;
	const numericLimit = Number(limitTime) || 0;
	const endTime = Date.now() + (numericLimit * 1000);

	const render = (time) =>{
		const min = String(Math.floor(time/60)).padStart(2, "0");
		const sec = String(time % 60).padStart(2, "0");
		const timeStr = min + sec;
		const timeHtml = timeStr.split('')
			.map(val => `<span class="inp">${val}</span>`)
			.join('');

		displayElement.innerHTML = timeHtml;
	}

	const tick = ()=>{
		const syncTime = endTime - Date.now();
		const remainingTime = Math.max(0, Math.ceil(syncTime / 1000));
		const nextDelay = syncTime % 1000 || 1000;

		render(remainingTime);

		if (remainingTime <= 0) {
			clearTimeout(tickSetTimeout);
			return
		}

		tickSetTimeout = setTimeout(tick, nextDelay);
	}
	tick();

	return {
		stop: () => clearTimeout(tickSetTimeout)
	}
}
```

## 커스텀 로컬 플러그인

> 기존 gatsby-transformer-remark 플러그인에 unist-util-visit 라이브러리 사용

### 1. 플러그인 추가

```js:title=plugins/gatsby-remark-table-wrapper/index.js
const visit = require('unist-util-visit')

module.exports = ({ markdownAST }) => {
  visit(markdownAST, 'table', (node, index, parent) => {
    const wrapper = {
      type: 'tableWrapper',
      data: {
        hName: 'div',
        hProperties: {
          className: ['table-wrapper']
        },
      },
      children: [JSON.parse(JSON.stringify(node))],
    }
    parent.children.splice(index, 1, wrapper)

    return [visit.SKIP, index + 1]
  })

  return markdownAST
}
```

- `unist-util-visit` : AST 탐색할때 사용 (기존에 사용하고있는 패키지가 CommonJS)  
  `visit(tree, '찾을 노드 타입', (node, index, parent)=>{})`
- `[visit.SKIP, index + 1]` : table > tableWrapper 교체 후 skip, index + 1 부터 다시 시작

```js:title=plugins/gatsby-remark-table-wrapper/package.json
